B.R0=new A.dp("Add Two 16-bit Numbers","Adds two 16-bit values and stores sum + carry","; [2800H..2801H] + [2802H..2803H]\nORG 2500H\n\nMVI C, 00H\nLHLD 2800H\nXCHG\nLHLD 2802H\nDAD D\nJNC STORE16\nINR C\nSTORE16: SHLD 2804H\nMOV A, C\nSTA 2806H\nHLT\n")
B.Rd=new A.dp("Subtract Two 16-bit Numbers","Subtracts two 16-bit values and stores result + borrow","; [2800H..2801H] - [2802H..2803H]\nORG 2500H\n\nMVI C, 00H\nLHLD 2800H\nXCHG\nLHLD 2802H\nMOV A, E\nSUB L\nSTA 2804H\nMOV A, D\nSBB H\nSTA 2805H\nJNC DONE16SUB\nINR C\nDONE16SUB: MOV A, C\nSTA 2806H\nHLT\n")
B.R7=new A.dp("Multiply Two 8-bit Numbers","Multiplies two 8-bit values via repeated addition","; [2500H] * [2501H] -> low at 2502H, high at 2503H\nORG 2100H\n\nLDA 2500H\nMOV B, A\nLDA 2501H\nMOV C, A\nMVI A, 00H\nMVI D, 00H\nMUL_LOOP: ADD B\nJNC NO_CARRY\nINR D\nNO_CARRY: DCR C\nJNZ MUL_LOOP\nSTA 2502H\nMOV A, D\nSTA 2503H\nHLT\n")
B.R2=new A.dp("Divide Two 8-bit Numbers","Divides two 8-bit values, stores quotient and remainder","; [2500H] / [2501H] -> quotient at 2503H, remainder at 2502H\nORG 2100H\n\nMVI C, 00H\nLDA 2500H\nMOV D, A\nLDA 2501H\nMOV B, A\nMOV A, D\nDIV_LOOP: CMP B\nJC DIV_DONE\nSUB B\nINR C\nJMP DIV_LOOP\nDIV_DONE: STA 2502H\nMOV A, C\nSTA 2503H\nHLT\n")
B.QY=new A.dp("Multiply Two 16-bit Numbers","Multiplies two 16-bit values via repeated addition","; [2200H..2201H] * [2202H..2203H]\nORG 2100H\n\nLHLD 2200H\nSPHL\nLHLD 2202H\nXCHG\nLXI H, 0000H\nLXI B, 0000H\nNEXT: DAD SP\nJNC LOOP\nINX B\nLOOP: DCX D\nMOV A, E\nORA D\nJNZ NEXT\nSHLD 2204H\nMOV L, C\nMOV H, B\nSHLD 2206H\nHLT\n")
B.QZ=new A.dp("Divide Two 16-bit Numbers","Divides two 16-bit values, stores quotient and remainder","; [2800H..2801H] / [2802H..2803H]\nORG 2500H\n\nLXI B, 0000H\nLHLD 2802H\nXCHG\nLHLD 2800H\nLOOP2: MOV A, L\nSUB E\nMOV L, A\nMOV A, H\nSBB D\nMOV H, A\nJC LOOP1\nINX B\nJMP LOOP2\nLOOP1: DAD D\nSHLD 2806H\nMOV L, C\nMOV H, B\nSHLD 2804H\nHLT\n")
