B.Re=new A.dp("Factorial (5!)","Calculate factorial of 5","; Compute 5! and store the result at 2100H\nORG 2000H\n\nMVI B, 05H      ; B = n\nMVI A, 01H      ; A = running result\nFACT_LOOP: MOV C, B\nCALL MUL_A_BY_C ; A = A * B\nDCR B\nMOV E, A\nMOV A, B\nCPI 01H\nMOV A, E\nJNZ FACT_LOOP\nSTA 2100H\nHLT\n\nMUL_A_BY_C: MOV D, A\nMVI A, 00H\nMUL_LOOP: ADD D\nDCR C\nJNZ MUL_LOOP\nRET\n")
